import { useState, useEffect } from 'react';
import { Container, Nav } from 'react-bootstrap';
import CardCreator from './components/CardCreator';
import FlashcardView from './components/FlashcardView';
import './App.css';

const STORAGE_KEY = 'memoryCardSet';

function App() {
  const [cards, setCards] = useState(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : [];
  });
  const [view, setView] = useState('create');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(cards));
  }, [cards]);

  const addCard = (question, answer) => {
    setCards((prev) => [...prev, { question, answer }]);
  };

  const clearCards = () => {
    setCards([]);
    localStorage.removeItem(STORAGE_KEY);
  };

  return (
    <div className="min-vh-100 bg-light">
      <Container className="py-4">
        <h1 className="text-center mb-4">Memory Card Generator</h1>
        <Nav variant="tabs" className="justify-content-center mb-4" activeKey={view} onSelect={setView}>
          <Nav.Item>
            <Nav.Link eventKey="create">Create Cards</Nav.Link>
          </Nav.Item>
          <Nav.Item>
            <Nav.Link eventKey="review" disabled={cards.length === 0}>
              Review Cards ({cards.length})
            </Nav.Link>
          </Nav.Item>
        </Nav>

        {view === 'create' ? (
          <CardCreator cards={cards} onAdd={addCard} onClear={clearCards} onStartReview={() => setView('review')} />
        ) : (
          <FlashcardView cards={cards} onBack={() => setView('create')} />
        )}
      </Container>
    </div>
  );
}

export default App;
